class Solution(object):
    def goodSubsetofBinaryMatrix(self, grid):
        """
        :type grid: List[List[int]]
        :rtype: List[int]
        """
        m = len(grid)
        n = len(grid[0])

        # Check if single row with all 0s exists
        for i in range(m):
            if all(grid[i][j] == 0 for j in range(n)):
                return [i]

        # Check if two rows form good subset
        for i in range(m):
            for j in range(i + 1, m):
                # Check if any column has both 0s
                good = True
                for col in range(n):
                    if grid[i][col] == 1 and grid[j][col] == 1:
                        good = False
                        break

                if good:
                    return [i, j]

        return []
